class Solution:
    def boxDelivering(self, boxes, portsCount, maxBoxes, maxWeight):
        n = len(boxes)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0
        for i in range(1, n + 1):
            weight = 0
            changes = 0
            count = 0
            j = i - 1
            while j >= 0:
                weight += boxes[j][1]
                count += 1
                if weight > maxWeight or count > maxBoxes:
                    break
                if j < i - 1 and boxes[j][0] != boxes[j + 1][0]:
                    changes += 1
                trips = 2 + changes
                if dp[j] + trips < dp[i]:
                    dp[i] = dp[j] + trips
                j -= 1
        return dp[n]

