from collections import deque
class Solution:
    def boxDelivering(self, boxes, portsCount, maxBoxes, maxWeight):
        n = len(boxes)
        change = [0] * n
        for i in range(1, n):
            change[i] = change[i - 1] + (1 if boxes[i][0] != boxes[i - 1][0] else 0)
        prefix_w = [0] * (n + 1)
        for i in range(n):
            prefix_w[i + 1] = prefix_w[i] + boxes[i][1]
        dp = [0] * (n + 1)
        dq = deque([0])
        left = 0
        for i in range(1, n + 1):
            while i - left > maxBoxes or prefix_w[i] - prefix_w[left] > maxWeight:
                left += 1
            while dq[0] < left:
                dq.popleft()
            dp[i] = dp[dq[0]] - change[dq[0]] + change[i - 1] + 2
            if i < n:
                val = dp[i] - change[i]
                while dq and (dp[dq[-1]] - change[dq[-1]]) >= val:
                    dq.pop()
                dq.append(i)
        return dp[n]

