var boxDelivering = function(boxes, portsCount, maxBoxes, maxWeight) {
    const n = boxes.length;
    const change = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        change[i] = change[i - 1] + (boxes[i][0] !== boxes[i - 1][0] ? 1 : 0);
    }
    const prefixW = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefixW[i + 1] = prefixW[i] + boxes[i][1];
    const dp = new Array(n + 1).fill(0);
    const dq = [0];
    let left = 0;
    for (let i = 1; i <= n; i++) {
        while (i - left > maxBoxes || prefixW[i] - prefixW[left] > maxWeight) left++;
        while (dq[0] < left) dq.shift();
        dp[i] = dp[dq[0]] - change[dq[0]] + change[i - 1] + 2;
        if (i < n) {
            const val = dp[i] - change[i];
            while (dq.length && (dp[dq[dq.length - 1]] - change[dq[dq.length - 1]]) >= val) dq.pop();
            dq.push(i);
        }
    }
    return dp[n];
};
